pseudocode:
# IMPLEMENTED: PipSuitHoop
class PipSuitHoop extends PipSuit:
  func spawn_props(origin : Vector3i, count : int) -> Array[PropSpawner]:
    var s : PropSpawner = PropSpawner.new()  # route = scored row
    s.modifiers = [PropScoreTalents.new()]   # scores via game.add_line_score
    return [s]

# IMPLEMENTED: PipSuitKnife
class PipSuitKnife extends PipSuit:
  func spawn_props(origin : Vector3i, count : int) -> Array[PropSpawner]:
    var s : PropSpawner = PropSpawner.new()  # mirrored entry side
    s.modifiers = [PropScoreProps.new()]     # plain cards duck under
    return [s]

# IMPLEMENTED: PipSuitBall
class PipSuitBall extends PipSuit:
  func spawn_props(origin : Vector3i, count : int) -> Array[PropSpawner]:
    var s : PropSpawner = PropSpawner.new()  # ballistic, mancala targets
    s.modifiers = [PropDropStatus.new(StatusJuggling)]
    return [s]

# IMPLEMENTED: PipSuitFire
class PipSuitFire extends PipSuit:
  func spawn_props(origin : Vector3i, count : int) -> Array[PropSpawner]:
    var s : PropSpawner = PropSpawner.new()  # skips talents + other Fire
    s.modifiers = [PropDropStatus.new(StatusBurning)]
    return [s]

class PipSuitGold extends PipSuit:
  func spawn_props(origin, count): return []  # no props
  func on_score(result) -> void:
    game.defer(func(): game.mint_card(TypeHeavy, RULES_GOLD))  # B10: defer deck mutation
    game.register_combo(combo_key())

class PipSuitElectric extends PipSuit:
  func spawn_props(origin : Vector3i, count : int) -> Array[PropSpawner]:
    var s : PropSpawner = PropSpawner.new()
    s.modifiers = [PropChainHop.new()]  # NEW PropModifier: route recomputed per hop,
    return [s]                          # pays game.add_line_score per link

# IMPLEMENTED: PipSuitFirework (special, excluded from PipSuit.STANDARD)
class PipSuitFirework extends PipSuit:
  func spawn_props(origin : Vector3i, count : int) -> Array[PropSpawner]:
    var s : PropSpawner = PropSpawner.new()  # rises, banks col score at top
    s.modifiers = [PropBankColumn.new()]
    return [s]

class PipRankRoman extends PipRankNumeral:
  func get_frame() -> int: return ROMAN_FRAMES + rank  # visuals only
  # comparisons untouched: PipComparator numeric fallback applies

class PipRankHeadliner extends PipRankNumeral:
  func on_compare_ranks(a, b) -> float:
    # answer both 1-adjacent and 13-adjacent as valid neighbors
    if is_ace(a): return best_of(compare_as(1, b), compare_as(14, b))
    return NAN  # fall through to numeric

# stub exists: HalfStepRank
class PipRankHalfStep extends PipRank:
  func on_compare_ranks(a, b) -> float:
    return compare_fractional(a, b)  # 5.5 sits between 5 and 6
  # Scoring: excluded from hand evaluation (returns no meld rank)

class PipRankFifteen extends PipRankNumeral:
  func on_score_row(row : Array[CardData]) -> void:
    for pair : Array[CardData] in neighbor_sums(row, data, 15):
      game.add_line_score(row_of(data), FIFTEEN_PTS)
      game.register_combo(combo_key())

class PipSuitBower extends PipSuit:
  func on_compare_suits(a, b) -> float:
    if in_scoring_pass(): return 1.0  # matches all suits for melds
    return NAN                        # stacking uses real comparisons
  func spawn_props(origin, count): return []

class PipRankHalf extends PipRank:
  func on_can_place_stack(stack, dest) -> Variant:
    if is_half(dest.top()) and is_half(stack.head()): return true  # co-slot
    return null
  # Scoring: co-slotted pair evaluates as one card of summed rank

# MultiSuit stub already commented in pip_comparator.gd
class PipSuitHarlequin extends PipSuit:
  var a : PipSuit; var b : PipSuit
  func on_compare_suits(x, y): return best_of(a.compare(x,y), b.compare(x,y))
  func spawn_props(origin, count): return a.spawn_props(origin,1) + b.spawn_props(origin,1)

class PipSuitFireKnife extends PipSuitHarlequin:
  func _init() -> void:
    a = PipSuitKnife.new()
    b = PipSuitFire.new()  # both spawn_props volleys fire per meld

class PipRankWild extends PipRank:
  var mimic : PipRank
  func on_anything(...) -> void:  # cheap: recompute only on revision change
    mimic = pick_from_row_hash(data, game.state.revision)  # deterministic, no RNG
  func on_compare_ranks(a, b): return mimic.on_compare_ranks(a, b)

class PipRankForgedAce extends PipRankNumeral:
  func on_score(result) -> void: game.add_line_score(row_of(data), FORGERY_PTS)
  func on_mod_triggered(mod) -> void:
    if mod is InspectionEffect:
      game.defer(func(): game.destroy_card(data); game.state.void_fame = true)

# IMPLEMENTED: TypePaper — the no-op default type
class TypePaper extends CardModifierType:
  pass  # exists so every card has a type slot filled

class TypeCanvas extends CardModifierType:
  var shrugged : bool = false  # per-show flag lives on GameData.type_state
  func on_game_start() -> void: game.state.type_state[data] = false
  func on_mod_triggered(mod) -> void:
    if mod is CardModifierStatus and not game.state.type_state[data]:
      game.state.type_state[data] = true
      game.defer(func(): data.remove_status(mod))

class TypeTicketStub extends CardModifierType:
  func trade_value() -> int: return 2 * RULES_BASE_VALUE  # shop layer
  # Scoring exclusion: card contributes no rank to melds

class TypeSawdust extends CardModifierType:
  func on_discard() -> void:
    game.state.slot_marks[locate(data)] = SAWDUST  # per-show state on GameData
  # scorer consults slot_marks in on_score and clears the mark

class TypeHelium extends CardModifierType:
  func on_append() -> void:
    game.defer(func(): game.raise_to_top(data))

class TypeAir extends CardModifierType:
  func on_stack_cards(stack) -> void:
    if not is_top(data, stack):
      game.defer(func(): Board.move_stack(game.state, data, Board.OnTop.new(stack.top())))

class TypeEarth extends CardModifierType:
  func on_stack_cards(stack) -> void:
    if not is_bottom(data, stack):
      game.defer(func(): Board.move_stack(game.state, stack.below(data), Board.OnTop.new(data)))

class TypeWater extends CardModifierType:
  func on_next() -> void:
    var dest : int = shortest_adjacent_column(data)
    if dest != -1:
      game.defer(func(): Board.move_stack(game.state, data, Board.ColumnEnd.new(1, dest)))

# stub exists: TypeStone — finish it as the Immovable material
class TypeStone extends CardModifierType:
  func on_can_grab_stack(stack) -> Variant:
    if stack.contains(data) and in_ring(data): return false  # deny wins
    return null
  func on_score(result) -> void: game.add_line_score(row_of(data), STONE_PTS)

class TypeRosin extends CardModifierType:
  func on_can_grab_stack(stack) -> Variant:
    if sits_on(stack.head(), data): return false
    return null
  func on_score_col(col) -> void: game.add_line_score(col_of(data), ring_bonus(data))

class TypeGlass extends CardModifierType:
  func on_score(result) -> void:
    game.add_line_score(row_of(data), base_points(data))  # doubling
    game.state.glass_counts[data] = game.state.glass_counts.get(data, 0) + 1
    if game.state.glass_counts[data] >= 3:
      game.defer(func(): game.destroy_card(data))

class TypeWax extends CardModifierType:
  func on_game_end() -> void:
    var heat : int = flames_shared_column_count(data)  # tracked on GameData
    data.rank = max(0, data.rank - heat)
    if data.rank == 0: game.defer(func(): game.destroy_card(data))

class TypeFlash extends CardModifierType:
  func on_score(result) -> void:
    if not game.state.flashed.has(data):
      game.state.flashed.append(data)  # per-show list on GameData (undo-safe)
      game.add_line_score(row_of(data), 2 * base_points(data))
    else:
      negate_score(result, data)  # NEEDS NEW HOOK: score negation seam

class TypeDigital extends CardModifierType:
  func on_discard() -> Variant:
    if on_board(data): return DENY  # NEEDS NEW HOOK: cancellable on_discard
    return null

class TypeNull extends CardModifierType:
  func on_compare_ranks(a, b): return NAN  # never stacks into runs
  # Scoring exclusion: contributes nothing; exists to occupy space

class TypeFirstAct extends CardModifierType:
  func on_append() -> void:
    game.defer(func(): game.raise_to_top(data))
  func on_next() -> void:
    if drawn_this_next(data): suppress_other_draws_this_column()  # enters alone

class TypeSecondAct extends CardModifierType:
  func on_append() -> void:
    game.defer(func(): game.insert_at_fraction(data, 0.5))

class TypeFinalAct extends CardModifierType:
  func on_append() -> void:
    game.defer(func(): game.sink_to_bottom(data))  # above Gold tokens
  func on_score(result) -> void:
    if game.state.draw_deck.is_empty(): game.add_line_score(row_of(data), CLOSER_MULT)

class TypeAutomaton extends CardModifierType:
  func on_next() -> void:
    if data.skill and data.skill.has_method(&'on_cue'):
      data.skill.call(&'on_cue')  # NEEDS NEW HOOK: on_cue (shared cue system)
  func can_manual_cue() -> bool: return false

class TypeBahurupiya extends CardModifierType:
  func on_game_start() -> void:
    var i : int = hash_pick(game.state.game_history_trimmed, CLASSES.size())
    data.meta.class_tag = CLASSES[i]  # no RNG: resume-persisted hash

class TypeOutlawed extends CardModifierType:
  func on_score(result) -> void:
    if game.town_tag() == &'pious': negate_score(result, data)  # see TypeFlash seam
    else: game.add_line_score(row_of(data), base_points(data))

class StampSpangle extends CardModifierStamp:
  func on_score(result) -> void:
    game.register_combo(combo_key())  # idempotent; counts once per act

class StampMarked extends CardModifierStamp:
  # StampGlobal-style: active from inside decks
  func on_active() -> void: game.view_hint_deck_position(data)  # if view: only

class StampBrassCheck extends CardModifierStamp:
  func on_mod_triggered(mod) -> void:
    if mod.data == data:
      game.defer(func(): game.mint_card_on_top(TypeHeavy, RULES_GOLD))

class StampGreasepaint extends CardModifierStamp:
  func extra_class_tag() -> StringName: return &'Clown'
  # group lookups (leaders, class counters) consult stamp tags too

class StampTopBilling extends CardModifierStamp:
  func trigger_priority() -> int: return -100  # NEEDS NEW HOOK: dispatch priority
  # run_all_mods sorts implementers by trigger_priority before board order

class StampGhostLight extends CardModifierStamp:
  func blocks_spotlight() -> bool: return false
  # CardModifier.is_active skips Ghost Light cards when scanning covers

# IMPLEMENTED: StampRevealing
class StampRevealing extends CardModifierStamp:
  func is_active_override() -> Variant: return true  # while on board

class StampMaxEffort extends CardModifierStamp:
  func on_score(result) -> void:
    if not run_state().exhausted.has(data):
      game.add_line_score(row_of(data), base_points(data))
      run_state().exhausted.append(data)  # cross-show state lives on RunState
  func on_game_end() -> void:
    if not appeared_this_show(data): run_state().exhausted.erase(data)

class StampUnderstudy extends CardModifierStamp:
  func on_mod_triggered(mod) -> void:
    if mod is DestructionEffect and was_directly_above(mod.target, data):
      game.defer(func(): data.skill = mod.target.skill.duplicate(); relink(data))

class StampMarotte extends CardModifierStamp:
  func on_mod_triggered(mod) -> void:
    if mod is DestructionEffect and mod.target == data:
      game.defer(func():
        var copy : CardData = data.duplicate_deep()  # RELINK backrefs after!
        GameData.relink_card_backrefs(copy)
        copy.rank = RANK_ONE; copy.stamp = null
        game.replace_card(data, copy))

class StampIronBody extends CardModifierStamp:
  func on_mod_triggered(mod) -> void:
    if mod.targets(data) and mod.is_hostile and not game.state.iron_used.has(data):
      game.state.iron_used.append(data)  # per-show, on GameData (undo-safe)
      mod.negate()  # NEEDS NEW HOOK: hostile-effect negation seam

class StampAscetic extends CardModifierStamp:
  func on_prop_passing(prop) -> Variant:
    if prop.is_hazard and prop.axis == ROW: return NEGATE_PASS
    return null

class StampUnpierceable extends CardModifierStamp:
  func on_prop_passing(prop) -> Variant:
    if prop.kind == KNIFE:
      prop.mark_missed(data)  # miss-counters still credit
      return NEGATE_PASS
    return null

class StampVine extends CardModifierStamp:
  func on_discard() -> Variant:
    if is_hazard_discard() and not run_state().vine_used.has(data):
      run_state().vine_used.append(data)  # once per TOUR: RunState
      return DENY  # NEEDS NEW HOOK: cancellable on_discard
    return null

class StampContractInk extends CardModifierStamp:
  func on_game_end() -> void:
    if appeared_this_show(data): run_state().ink_streak[data] = 0
    else:
      run_state().ink_streak[data] += 1
      if run_state().ink_streak[data] >= 2: run_state().remove_from_deck(data)
  func on_score(result): game.add_line_score(row_of(data), INK_PTS * shows_played(data))

# IMPLEMENTED: StampDoubleTrigger
class StampDoubleTrigger extends CardModifierStamp:
  func on_mod_triggered(mod) -> void:
    if mod.data == data and not mod.is_echo:
      mod.retrigger_once()  # echo flag prevents infinite loops

# IMPLEMENTED: StampGlobal
class StampGlobal extends CardModifierStamp:
  func is_active_override() -> Variant: return true  # any stage

class StampEncore extends CardModifierStamp:
  func on_game_end() -> void:
    if triggered_this_show(data) and hash_coin(game.state.game_history_trimmed, data):
      data.skill.call(&'on_trigger')  # deterministic coin: no RNG in resolution
      game.register_combo(combo_key())

class StampLloyds extends CardModifierStamp:
  func on_mod_triggered(mod) -> void:
    if mod.targets(data) and mod.is_hostile and not run_state().policy_paid.has(data):
      run_state().policy_paid.append(data)
      mod.negate()  # shared negation seam (see Iron Body)
      game.defer(func(): game.mint_card(TypeHeavy, RULES_GOLD, 2))

class StampKuroko extends CardModifierStamp:
  func blocks_spotlight() -> bool: return false
  func is_targetable() -> bool: return false  # hazard target-pickers skip it

class StampTitle extends CardModifierStamp:
  func apparent_rarity() -> int: return true_rarity(data) + 1
  # pool generation reads true_rarity; effects read apparent_rarity

class StampIllustrated extends CardModifierStamp:
  func stamp_capacity() -> int: return 999
  func on_active() -> void:
    if data.skill: data.skill = null  # the canvas has no room for an act

class StampAvatar extends CardModifierStamp:
  var persona : CardData  # weakref via CardModifier.data pattern
  func apparent_identity() -> CardData: return persona
  func on_score(result) -> void:
    game.state.avatar_scores[data] += 1
    if game.state.avatar_scores[data] >= 3: reveal(data)

class StampGrip extends CardModifierStamp:
  func on_can_grab_stack(stack) -> Variant:
    if stack.head() == data: return true  # whitelist; blacklist still wins
    return null

class StampWeddingBand extends CardModifierStamp:
  var partner : CardData
  func on_append() -> void:
    game.defer(func(): game.deck_place_adjacent(data, partner))

class StampBelt extends CardModifierStamp:
  func on_score(result) -> void: game.add_line_score(row_of(data), base_points(data))
  func on_game_end() -> void:
    if game.boss_tag() == &'belt_challenge' and not game.won():
      profile().belt_holder = game.boss_id()  # profile-level, crosses runs

# IMPLEMENTED: TypeInput (rules deck zone-header)
class TypeInput extends CardModifierType:
  func on_next() -> void:
    Board.move_stack(state, held_stack(), Board.ColumnEnd.new(1, my_column()))
    game.draw_card(my_column())  # engine rule: combo_key() -> ''

# IMPLEMENTED: SkillAdderInputLower / ZoneAdder
class ZoneAdder extends CardModifierSkill:
  func on_game_start() -> void:
    Board.add_column(state, LOWER)  # rank identifies the duplicate
  func combo_key(hook) -> String: return ''

# IMPLEMENTED: SkillGrabberOgLower
class SkillGrabberOgLower extends CardModifierSkill:
  func on_can_grab_stack(stack) -> Variant:
    return is_run(stack) and not has_adjacent_same_suit(stack)
  func combo_key(hook) -> String: return ''

# IMPLEMENTED: SkillPlacerOgLower
class SkillPlacerOgLower extends CardModifierSkill:
  func on_can_place_stack(stack, dest) -> Variant:
    return legal_join(stack.head(), dest.top())
  func combo_key(hook) -> String: return ''

# IMPLEMENTED: SkillScorerCascadeLower
class SkillScorerCascadeLower extends CardModifierSkill:
  func on_run_scorer() -> void:
    for row : Array[CardData] in state.lower_rows(): score_row(row)
    for col : Array[CardData] in state.lower_cols(): score_col(col)
  func combo_key(hook) -> String: return ''

# IMPLEMENTED: SkillEvalPokerBest
class SkillEvalPokerBest extends CardModifierSkill:
  func on_score_row(row : Array[CardData]) -> void:
    var r : Scoring.Result = Scoring.best_hand(row)
    game.add_line_score(row_index(row), Scoring.ScoreModel.points(r))
  func combo_key(hook) -> String: return ''

class RuleFreeUndo extends CardModifierSkill:
  func on_next() -> void:
    game.state.free_undos = 1  # per-turn, on GameData (undo-safe, ha)
  func combo_key(hook) -> String: return ''

class StampEvident extends CardModifierStamp:  # stamp ON a rule card
  func on_active() -> void:
    if game.view: game.view.announce_rule(data)  # board banner; data untouched

class RuleSoundcheck extends CardModifierSkill:
  func on_game_start() -> void:
    game.state.rehearsal_moves = 1  # try_place decrements; no save_state commit
  func combo_key(hook) -> String: return ''

class RulePatience extends CardModifierSkill:
  func on_next() -> void: game.state.patience = PATIENCE_MAX
  func on_stack_cards(stack) -> void:
    game.state.patience -= 1
    if game.state.patience <= 0: game.defer(func(): game.force_next())
  func on_mod_triggered(mod) -> void:
    if first_this_act(mod): game.state.patience += 1

class RuleBooking extends CardModifierSkill:
  func on_game_start() -> void: game.state.booking = terms  # from map node
  func on_after_score() -> void:
    if violates(game.state, terms): game.state.booking_broken = true
  func on_game_end() -> void:
    game.apply_booking(game.state.booking_broken)  # fame swing both ways
  func combo_key(hook) -> String: return ''

class RuleBrassRing extends CardModifierSkill:
  func on_next() -> void:
    game.state.ring_col = (game.state.ring_col + 1) % state.column_count()
  func on_score_col(col) -> void:
    if col_index(col) == game.state.ring_col:
      game.add_line_score(col_index(col), col_total(col))
      game.defer(func(): game.mint_card(TypeTicketStub))

class RuleRings extends CardModifierSkill:
  func on_score_row(row : Array[CardData]) -> void:
    var mult : int = 1 + row_index(row) / 5
    game.add_line_score(row_index(row), row_base(row) * (mult - 1))
  func combo_key(hook) -> String: return ''

class RuleSymmetry extends CardModifierSkill:
  func on_score_col(col : Array[CardData]) -> void:
    var r : Scoring.Result = Scoring.best_hand(col)
    if r.valid():
      game.add_line_score(col_index(col), Scoring.ScoreModel.points(r))
      game.register_combo(combo_key())

class RuleContrary extends CardModifierSkill:
  func on_compare_ranks(a, b) -> float: return -PipComparator.numeric(a, b)
  func on_score_row(row : Array[CardData]) -> void:
    var r : Scoring.Result = Scoring.worst_hand(row)  # inverts SkillEvalPokerBest
    game.add_line_score(row_index(row), Scoring.ScoreModel.points(r))

class SecretSwordSwallow extends CardModifierSkill:  # rules_deck, hidden
  func on_score_col(col : Array[CardData]) -> void:
    if is_perfect_descending(col) and col.size() >= state.row_count():
      game.add_line_score(col_index(col), SWALLOW_BONUS)
      game.register_combo(combo_key())

class SecretDeadMansHand extends CardModifierSkill:  # rules_deck, hidden
  func on_score_row(row : Array[CardData]) -> void:
    var r : Scoring.Result = Scoring.best_hand(row)
    if r.archetype == TWO_PAIR and ranks_are(r, [ACE, EIGHT]):
      game.add_line_score(row_index(row), JACKPOT)
      run_state().queue_map_event(&'ghost_of_deadwood')

class SecretFortyTwo extends CardModifierSkill:  # rules_deck, hidden
  func on_after_score() -> void:
    for line : int in state.row_count():
      if state.row_score(line).to_int() + state.col_score(line).to_int() == 42:
        game.register_combo(combo_key() + str(line))  # 3 distinct keys max

class SecretThreeRings extends CardModifierSkill:  # rules_deck, hidden
  func on_after_score() -> void:
    if full_row_hands_this_act(state) >= 3:
      profile().unlock(&'rule_third_zone')  # profile flag, crosses runs
      game.register_combo(combo_key())

class SecretVoladores extends CardModifierSkill:  # rules_deck, hidden
  func on_game_end() -> void:
    if thirteen_descents_this_show(state) >= 4:
      run_state().bank_fame(52 * BASE_FAME)
      profile().unlock(&'calendar_cardback')

class SecretYakuza extends CardModifierSkill:  # rules_deck, hidden
  func on_score_row(row : Array[CardData]) -> void:
    if ranks_exactly(row, [8, 9, 3]):
      game.add_line_score(row_index(row), WORTHLESS_JACKPOT)
      game.register_combo(combo_key())

class SkillButterfly extends CardModifierSkill:
  func on_cue() -> void:  # NEEDS NEW HOOK: on_cue (shared cue system)
    game.defer(func():
      game.mint_card_at(TypePaper, RANK_ONE, target_col(), 2)
      game.register_combo(combo_key()))

class SkillMysteryBox extends CardModifierSkill:
  func on_game_start() -> void:
    var pool : Array[GDScript] = ModsList.skill_pool()  # var not const (typed array)
    data.skill = pool[hash_pick(run_state().world_seed, pool.size())].new()
    GameData.relink_card_backrefs(data)  # relink after modifier swap

class SkillEggBag extends CardModifierSkill:
  var held : CardData  # holder keeps the CardData itself (weakref rule)
  func on_cue() -> void:  # NEEDS NEW HOOK: on_cue
    game.defer(func(): held = game.take_top_discard())
  func on_score(result) -> void:
    if held: game.defer(func(): game.place_in_entrance(held); held = null)

class SkillSawing extends CardModifierSkill:
  func on_cue() -> void:  # NEEDS NEW HOOK: on_cue
    var t : CardData = cue_target()
    game.defer(func():
      game.split_card(t, ceil(t.rank / 2.0), floor(t.rank / 2.0))
      game.state.exhausted_cues.append(data))

class SkillMisdirection extends CardModifierSkill:
  func spotlight_grants() -> Array[CardData]:  # consulted by is_active scan
    return [top_covered(left_col(data)), top_covered(right_col(data))]

class SkillDuck extends CardModifierSkill:
  var stored : Array[CardData] = []  # holder keeps CardData (weakref rule)
  func on_card_dropped_on(dropped) -> void:
    game.defer(func(): stored.append(game.extract_card(dropped)))
  func on_cue() -> void:  # NEEDS NEW HOOK: on_cue
    game.defer(func(): game.place_in_entrance(stored.pop_back()))

class SkillPandora extends CardModifierSkill:
  func on_game_start() -> void:
    data.skill = random_skill_hash(run_state(), data)  # deterministic
    GameData.relink_card_backrefs(data)
  func on_game_end() -> void:
