    var under : CardData = card_below(data)
    return under.rank if under else 0
  func on_compare_ranks(a, b) -> float:
    if a == data: return PipComparator.numeric_of(effective_rank(), b)
    return NAN

class SkillImitator extends CardModifierSkill:
