class SkillHippo extends CardModifierSkill:
  var eaten : Array[CardData] = []  # holder keeps CardData (weakref rule)
  func on_card_dropped_on(dropped) -> void:
    if data.rank.value >= 13: return
    game.defer(func():
      eaten.append(game.extract_card(dropped))
      data.rank.value = min(13, data.rank.value + dropped.rank.value))
  func on_game_end() -> void:
    for c : CardData in eaten: game.return_to_deck(c)

