  func on_next() -> void:
    if game.state.turn_count % 2 == 0:
      var from : Vector3i = locate(data)
      game.defer(func():
        Board.move_stack(game.state, data, next_slot(data))
        game.state.slot_marks[from] = BLESSED)

class SkillDragon extends CardModifierSkill:
  func on_score_col(col : Array[CardData]) -> void:
    var run : Array[CardData] = run_containing(data, col)
    if run.size() >= 4: game.state.dragon_stack = run  # flagged as movable unit
  func on_can_grab_stack(stack) -> Variant:
    if stack == game.state.dragon_stack: return true
    return null

class SkillFadista extends CardModifierSkill:
  func on_score(result) -> void:
    game.add_line_score(row_of(data), GRIEF_PTS * run_state().cards_lost_count)
    game.register_combo(combo_key())

class SkillCastell extends CardModifierSkill:
  func on_score_col(col : Array[CardData]) -> void:
    var s : Array[CardData] = stack_containing(data)
    if s.size() >= 6 and s.back().rank.value == lowest_rank_in(s):
      game.add_line_score(col_index(col), CASTELL_BONUS)
      game.register_combo(combo_key())

class SkillStraitjacket extends CardModifierSkill:
  func on_can_grab_stack(stack) -> Variant:
    if stack.contains(data) and not game.state.escaped.has(data): return false
    return null
  func on_score_col(col) -> void:
    if col_index(col) == col_of(data) and not game.state.escaped.has(data):
      game.state.escaped.append(data)
      game.add_line_score(col_index(col), ESCAPE_PTS)
      game.register_combo(combo_key())

class SkillBlockhead extends CardModifierSkill:
  func on_prop_passing(prop) -> Variant:
    if prop.kind == KNIFE and not game.state.blockhead_used.has(data):
      game.state.blockhead_used.append(data)
      game.add_line_score(row_of(data), NAIL_PTS)
      game.register_combo(combo_key())
      return NEGATE_PASS
    return null

class SkillTargetGirl extends CardModifierSkill:
  func on_prop_passed(prop) -> void:
    if prop.kind == KNIFE and prop.missed(data):
      game.add_line_score(row_of(data), MISS_PTS)
      game.register_combo(combo_key())

class SkillMilkCan extends CardModifierSkill:
  var held : CardData  # holder keeps the CardData itself (weakref rule)
  func on_cue() -> void:  # NEEDS NEW HOOK: on_cue
    if held: game.defer(func(): game.place_in_entrance(held); held = null)
    else: game.defer(func(): held = game.extract_card(cue_target()))

class SkillEscapeMap extends CardModifierSkill:
  func on_discard() -> void:
    run_state().reveal_fog(FOG_RADIUS)  # map-layer effect
    game.register_combo(combo_key())

class SkillMime extends CardModifierSkill:
  func on_mod_triggered(mod) -> void:
    if mod.is_hostile and in_same_stack(mod.target, data) and not game.state.mime_spent.has(data):
      game.state.mime_spent.append(data)
      mod.retarget(data)  # hostile retarget seam (see Rodeo Clown)

class SkillInvisibleWall extends CardModifierSkill:
  func on_cue() -> void: game.state.walled_col = cue_target_col()
  func on_can_place_stack(stack, dest) -> Variant:
    if dest.column() == game.state.walled_col: return false
    return null
  func on_next() -> void: game.state.walled_col = -1

class SkillStuntDouble extends CardModifierSkill:
  var star : CardData
  func on_mod_triggered(mod) -> void:
    if mod.is_hostile and mod.target == star and not game.state.double_spent.has(data):
      game.state.double_spent.append(data)
      mod.retarget(data)  # hostile retarget seam

class SkillBrodie extends CardModifierSkill:
  func on_game_end() -> void:
    run_state().brodie_bank += CLAIM_FAME
    run_state().bank_fame(CLAIM_FAME)
  func on_mod_triggered(mod) -> void:
    if mod is InspectionEffect and mod.targets(data):
      run_state().bank_fame(-2 * run_state().brodie_bank)

class SkillEdith extends CardModifierSkill:
  func on_cue() -> void:  # NEEDS NEW HOOK: on_cue
    var blade : CardData = cue_target()
    if blade.suit is PipSuitKnife:
      game.defer(func():
        game.destroy_card(blade)
        data.rank.value += blade.rank.value)

class SkillFireBreather extends CardModifierSkill:
  func on_cue() -> void:  # NEEDS NEW HOOK: on_cue
    for c : CardData in row_cards(row_of(data)):
      var st : StatusBurning = StatusBurning.new()  # duplicate per application
      game.defer(func(): c.add_status(st))
    game.defer(func(): data.add_status(StatusExhausted.new()))

class SkillRegurgitator extends CardModifierSkill:
  var gullet : Array[CardData] = []  # holder keeps CardData (weakref rule)
  func on_cue() -> void:  # NEEDS NEW HOOK: on_cue
    if cue_mode() == SWALLOW and gullet.size() < 3:
      game.defer(func(): gullet.append(game.extract_card(cue_target())))
    else:
      game.defer(func(): game.place_in_entrance(gullet.pop_at(cue_index())))

class SkillHungerArtist extends CardModifierSkill:
  # StampGlobal-style: counts shows from inside the deck
  func on_game_end() -> void:
    if not appeared_this_show(data): run_state().fast_days[data] += 1
  func on_score(result) -> void:
    game.add_line_score(row_of(data), FAST_PTS * run_state().fast_days.get(data, 0))
    run_state().fast_days[data] = 0
    game.register_combo(combo_key())

class SkillWaterCell extends CardModifierSkill:
  func on_next() -> void:
    var locks : int = game.state.cell_locks.get(data, 3)
    if lock_condition_met(data, locks): game.state.cell_locks[data] = locks - 1
  func on_score(result) -> void:
    if game.state.cell_locks.get(data, 3) == 0:
      game.add_line_score(row_of(data), ESCAPE_JACKPOT)
      game.register_combo(combo_key())

class SkillBuriedAlive extends CardModifierSkill:
  func on_cue() -> void:  # NEEDS NEW HOOK: on_cue
    var c : CardData = cue_target()
    run_state().bury(c, 2)  # RunState timer; re-mints at +1 rarity on expiry
    if hash_roll(run_state().world_seed, c, 13) == 0:
      run_state().mark_lost(c)  # the grave keeps this one

class SkillHoldout extends CardModifierSkill:
  var sleeve : CardData  # RunState-held: survives show teardown
  func on_cue() -> void:  # NEEDS NEW HOOK: on_cue
    game.defer(func():
      Board.place_card(game.state, sleeve, cue_slot()); sleeve = null)
  func on_mod_triggered(mod) -> void:
    if mod is SearchEffect and sleeve: run_state().mark_lost(sleeve)

class SkillKneelingDevil extends CardModifierSkill:
  func on_game_start() -> void:
    game.defer(func(): column_debuff(col_of(data)))  # the devil dances
  func on_game_end() -> void:
    if run_state().at_final_city and run_state().devil_kept_all_tour(data):
      run_state().transform_card(data, &'legendary_blessing')  # it kneels

class SkillSearingKnife extends CardModifierSkill:
  func on_score_col(col : Array[CardData]) -> void:
    if col_index(col) != col_of(data): return
    game.add_line_score(col_index(col), 2 * col_total(col))
    game.state.locked_cols[col_index(col)] = 2  # turns; on_next decrements
  func on_can_place_stack(stack, dest) -> Variant:
    if game.state.locked_cols.get(dest.column(), 0) > 0: return false
    return null

class SkillCapoeirista extends CardModifierSkill:
  func extra_class_tag() -> StringName: return &'Dancer'  # the registration
  func true_class_tag() -> StringName: return &'Escape Artist'
  func on_score(result) -> void:
    if game.town_bans(&'Escape Artist'):
      game.add_line_score(row_of(data), DEFIANCE_PTS)  # scores double under a ban
      game.register_combo(combo_key())

class SkillWallOfDeath extends CardModifierSkill:
  func on_score_col(col : Array[CardData]) -> void:
    if abs(col_index(col) - col_of(data)) == 1:
      game.add_line_score(col_index(col), WALL_MULT)
  func on_game_end() -> void:
    for c : CardData in adjacent_column_cards(data):
      c.add_status(StatusExhausted.new())  # duplicate per application

class SkillBottomDeal extends CardModifierSkill:
  func on_cue() -> void:  # NEEDS NEW HOOK: on_cue (shared cue system)
    game.state.deal_from_bottom = true  # TypeInput.on_next consults; resets on Next end
    game.register_combo(combo_key())

class SkillXRay extends CardModifierSkill:
  # inverted activation: needs StampRevealing-style override while covered
  func is_active_override() -> Variant: return is_covered(data)
  func on_active() -> void:
    if game.view: game.view.reveal_hidden_all()  # info only, data untouched

class SkillSecondSight extends CardModifierSkill:
  var partner : CardData
  func on_active() -> void:
    if on_board(partner) and game.view: game.view.reveal_deck_top(true)
  func on_deactive() -> void:
    if game.view: game.view.reveal_deck_top(false)

class SkillLuckyStreak extends CardModifierSkill:
  func on_game_start() -> void:
    run_state().rerolls += 1
    game.state.reroll_stream_advance = true  # forked RNG stream per action

class SkillMulligan extends CardModifierSkill:
  func on_next() -> void:
    game.state.entrance_discards = 1 + copies_in_play(SkillMulligan) - 1
  # GameView: entrance cards gain a discard affordance while quota > 0

class SkillZora extends CardModifierSkill:
  # StampGlobal-style activation: works from any stage
  func on_active() -> void:
    if game.view: game.view.pin_next_draw_preview(true)

class SkillGriot extends CardModifierSkill:
  func on_game_end() -> void:
    run_state().carryover = game.state.total.multiplied(0.2)  # BigNumber, capped
    run_state().remembered = pick_effect_ui(game.state.fired_this_show)
  func on_game_start() -> void:
    game.state.total = run_state().carryover
    replay_effect(run_state().remembered)

class SkillWaxGold extends CardModifierSkill:
  func on_score(result) -> void:
    game.add_line_score(row_of(data), WAX_PTS)
    run_state().wax_count[data] = run_state().wax_count.get(data, 0) + 1
    if run_state().wax_count[data] >= 5: run_state().gold_unlocked.append(data)
    if run_state().gold_unlocked.has(data): game.register_combo(combo_key())

class SkillRider extends CardModifierSkill:
  func on_stack_cards(stack) -> void:
    if violates_rider(data, locate(data)): game.state.rider_broken.append(data)
  func on_score(result) -> void:
    if game.state.rider_broken.has(data): negate_score(result, data)
    else: game.add_line_score(row_of(data), base_points(data))

class SkillSystem extends CardModifierSkill:
  func on_after_score() -> void:
    var m : float = 0.5 if run_state().system_exposed else 1.0
    game.add_line_score(0, PROPHECY_PTS * game.state.combo_classes.size() * m)
  func on_mod_triggered(mod) -> void:
    if mod is InspectionEffect and mod.targets(data): run_state().system_exposed = true

class SkillSpiritCabinet extends CardModifierSkill:
  # inverted activation: active only while covered
  func is_active_override() -> Variant: return is_covered(data)
  func spotlight_grants() -> Array[CardData]:
    return column_cards(col_of(data))  # whole column spotlit via the cabinet

class SkillCliffhanger extends CardModifierSkill:
  func on_game_end() -> void:
    if game.state.cliffhanger_armed:
      run_state().next_goal_scale = 0.7
      run_state().cliff_debt = pending(data)
  # next show: on_game_end checks data scored, else bank_fame(-2 * discount)

class SkillDrumroll extends CardModifierSkill:
  var last_meld : Scoring.Result
  func on_score(meld) -> void: last_meld = meld            # track
  func on_after_score() -> void:
    game.add_line_score(last_meld.line, DRUMROLL_MULT)     # boost the closer
    game.register_combo(combo_key())

class SkillSparkler extends CardModifierSkill:
  func on_score(result) -> void:
    game.add_line_score(col_of(data), SPARK_PTS)  # column gutter: multiplied by row axis
    game.register_combo(combo_key())

class SkillSlicedBread extends CardModifierSkill:
  func on_score(result) -> void:
    var gap : int = distance_to_same_suit_below(data)  # -1 if none
    if gap > 0:
      game.add_line_score(col_of(data), BREAD_PTS * gap)
      game.register_combo(combo_key())

class SkillPokerCrown extends CardModifierSkill:
  func on_score(result) -> void:
    var five : Array[CardData] = data_and_four_above(data)
    var r : Scoring.Result = Scoring.best_hand(five)
    if r.valid():
      game.add_line_score(col_of(data), Scoring.ScoreModel.points(r))
      game.register_combo(combo_key())

class SkillColumnPoker extends CardModifierSkill:
  func on_score_col(col : Array[CardData]) -> void:
    if col_index(col) != col_of(data): return
    for band : Array[CardData] in bands_of_five(col):
      var r : Scoring.Result = Scoring.best_hand(band)
      if r.valid(): game.add_line_score(col_index(col), Scoring.ScoreModel.points(r))
    game.register_combo(combo_key())

class SkillCalliope extends CardModifierSkill:
  func on_after_score() -> void:
    for tag : StringName in classes_scored_this_act(game.state):
      game.register_combo(combo_key() + String(tag))

class SkillKite extends CardModifierSkill:
  var aloft : CardData  # holder keeps CardData (weakref rule)
  func on_cue() -> void:  # NEEDS NEW HOOK: on_cue
    game.defer(func(): aloft = game.extract_card(cue_target()))
  func on_next() -> void:
    game.state.kite_turns += 1
    if game.state.kite_turns == chosen_return():
      aloft.rank.value += min(3, game.state.kite_turns)
      game.defer(func(): game.place_in_entrance(aloft))

class SkillSteelpan extends CardModifierSkill:
  func on_cue() -> void:  # NEEDS NEW HOOK: on_cue
    if game.state.steelpan_used: return
    game.state.steelpan_used = true
    var junk : CardData = cue_target()
    if junk.skill == null:
      junk.skill = SkillPanNote.new()  # small row-meld bonus skill
      GameData.relink_card_backrefs(junk)

class SkillBootCode extends CardModifierSkill:
  func on_after_score() -> void:
    for c : CardData in row_cards(row_of(data)):
      silent_buff(c, BOOT_PTS)  # bypasses _note_mod_fired: no on_mod_triggered
    game.register_combo(combo_key())  # the CODE registers once; the passes never do

class SkillFanchant extends CardModifierSkill:
  func on_after_score() -> void:
    for meld : Scoring.Result in game.state.melds_this_act:
      if meld.raised_combo:
        game.add_line_score(meld.line, meld.points * 0.25)
    game.register_combo(combo_key())

class SkillAvalanche extends CardModifierSkill:
  func on_after_score() -> void:
    var n : int = game.state.board_cards().size()
    game.state.goal = game.state.goal.minus(n * AVALANCHE_RATE)  # BigNumber
    game.register_combo(combo_key())

class SkillNinot extends CardModifierSkill:
  func on_cue() -> void: run_state().ninot_bank += cue_amount()
  func on_game_end() -> void:
    if run_state().at_final_city:
      run_state().bank_fame(3 * run_state().ninot_bank)
      if hash_roll(run_state().world_seed, data, 20) == 0:
        profile().pardoned_ninot = true  # crosses runs

class SkillGrandSpec extends CardModifierSkill:
  func on_after_score() -> void:
    if all_columns_scored(game.state):
      game.state.combo_bonus_mult = 2.0  # applied in apply_act_score
      game.register_combo(combo_key())

class SkillDuende extends CardModifierSkill:
  func on_after_score() -> void:
    if game.state.combo_classes.size() >= 5 and all_melds_raised_u(game.state):
      game.state.combo_bonus_mult = 3.0
      if game.view: game.view.duende_moment()  # the one un-buyable animation
      game.register_combo(combo_key())

class SkillFairyFloss extends CardModifierSkill:
  func on_score(result) -> void:
    for n : CardData in adjacent_cards(data):
      var st : StatusSweetened = StatusSweetened.new()  # +1 rank, expires on_game_end
      game.defer(func(): n.add_status(st))
    game.register_combo(combo_key())

class SkillPinkLemonade extends CardModifierSkill:
  func on_score_row(row : Array[CardData]) -> void:
    if row_has_suit(row, PipSuitFire) and row_has_class(row, &'Concessions'):
      game.add_line_score(row_index(row), LEMONADE_PTS)
      game.defer(func(): game.draw_card(col_of(data)))
      game.register_combo(combo_key())

class SkillPopcorn extends CardModifierSkill:
  func on_score_col(col : Array[CardData]) -> void:
    if col.size() >= 4:
      game.defer(func(): game.draw_card(col_index(col)))
      game.register_combo(combo_key())

class SkillGreaseJoint extends CardModifierSkill:
  func on_game_start() -> void:
    game.defer(func():
      game.discard_from_deck_bottom()
      game.draw_card(col_of(data)))
    game.register_combo(combo_key())

class SkillCandyButcher extends CardModifierSkill:
  func on_score_row(row : Array[CardData]) -> void:
    if row.size() >= 5 and Scoring.best_hand(row).valid():
      game.defer(func(): game.mint_card(TypeTicketStub))
      game.register_combo(combo_key())

class SkillCheatDay extends CardModifierSkill:
  func on_game_end() -> void:
    if game.won() and game.state.draw_deck.size() > 0:
      for c : CardData in game.state.draw_deck:
        c.rank.value += 1
      game.register_combo(combo_key())

class SkillMealCall extends CardModifierSkill:
  func on_cue() -> void:  # NEEDS NEW HOOK: on_cue
    if game.state.meal_called: return
    game.state.meal_called = true
    for c : CardData in game.state.board_cards():
      if has_negative_status(c):
        game.defer(func(): c.remove_status(first_negative(c)))
    game.register_combo(combo_key())

class SkillIncubator extends CardModifierSkill:
  func on_next() -> void:
    for c : CardData in cards_below(data):
      if has_negative_status(c): game.defer(func(): c.remove_status(first_negative(c)))
      elif c.rank.value < c.rank.original: c.rank.value += 1
      game.register_combo(combo_key())

class TypeTailorsDummy extends CardModifierType:
  func stamp_capacity() -> int: return 2
  func skill_capacity() -> int: return 0  # a dummy performs nothing

class SkillFitting extends CardModifierSkill:
  func on_game_start() -> void:
    var n : CardData = highest_neighbor(data)
    if n and n.stamp:
      data.stamp = n.stamp.duplicate()  # expires: cleared in on_game_end
      GameData.relink_card_backrefs(data)

class SkillHikinuki extends CardModifierSkill:
  func on_score(result) -> void:
    var reserve : CardModifierStamp = run_state().stamp_reserve.pop_front()
    if reserve:
      run_state().stamp_reserve.push_back(data.stamp)
      data.stamp = reserve; GameData.relink_card_backrefs(data)
      game.register_combo(combo_key())

class SkillWardrobeTrunk extends CardModifierSkill:
  var reserve : CardModifierStamp
  func on_cue() -> void:  # NEEDS NEW HOOK: on_cue
    var t : CardData = cue_target()
    if reserve and t.stamp == null:
      t.stamp = reserve; reserve = null
      GameData.relink_card_backrefs(t)

class SkillHanafuda extends CardModifierSkill:
  func on_game_start() -> void:
    var banned : PipSuit = game.town_banned_suit()
    if banned:
      for c : CardData in game.state.all_player_cards():
        if same_class(c.suit, banned): game.state.reskinned.append(c)
  # PipComparator: reskinned cards answer suit checks as their neighbor's suit

class SkillCheapPop extends CardModifierSkill:
  func on_score(result) -> void:
    game.add_line_score(row_of(data), CHEAP_POP_PTS)  # small, town-independent
    game.register_combo(combo_key())

class SkillChainCommon extends CardModifierSkill:
