  func is_active_override() -> Variant: return is_covered(data)
  func on_score_row(row : Array[CardData]) -> void:
    if is_covered(data):
      score_as_copy(data, most_valuable_in(row))
      game.register_combo(combo_key())

class SkillWhiteElephant extends CardModifierSkill:
  func on_score(result) -> void:
    game.add_line_score(row_of(data), ELEPHANT_PTS)
    game.register_combo(combo_key())
  func on_game_end() -> void:
    if not scored_this_show(data):
      game.defer(func(): game.consume_gold_or_rank(1))

class SkillAdvanceCampaign extends CardModifierSkill:
