    var a : GDScript = most_fired_effect(run_state(), 0)
    var b : GDScript = most_fired_effect(run_state(), 1)
    data.skill = ComposedSkill.new(a, b)  # NEEDS NEW SYSTEM: skill composition
    profile().dubplates.append(data)

class SkillChainRare extends CardModifierSkill:
  func on_get_possible_boosters(pool) -> void:
    pool.scale_rarity_weight(RARITY_EPIC, 2.0)

class SkillPressBribery extends CardModifierSkill:
  func on_game_end() -> void:
    if not game.won() and not run_state().bribe_spent:
      run_state().bribe_spent = true
      game.override_outcome(WIN_FAKED)  # fame banks 0; tour continues
    elif run_state().at_final_city and not run_state().bribe_spent:
      game.override_outcome(WIN)

class SkillRedWagon extends CardModifierSkill:
  func on_compare_ranks(a, b) -> float:
    if is_gold_token(card_of(a)) and in_deck(card_of(a)):
      return 0.0  # gold answers any run adjacency while the Wagon is lit
    return NAN

class SkillChainEpic extends CardModifierSkill:
  func on_get_possible_boosters(pool) -> void:
    pool.scale_rarity_weight(RARITY_LEGENDARY, 2.0)

class SkillEyeOfGod extends CardModifierSkill:
  # StampGlobal-style activation
  func on_active() -> void:
