# SEAM: hooks are duck-typed methods — nothing stops a mod INVOKING another
# mod's hook; the contract question is attribution (_note_mod_fired).
class SkillCueCard extends CardModifierSkill:
  func on_cue() -> void:  # NEEDS NEW HOOK: on_cue
    var t : CardData = cue_adjacent_target()
    if t.skill and t.skill.has_method(&'on_trigger'):
      game.invoke_mod(t.skill, &'on_trigger')  # routes through run_all_mods
      # so StampDoubleTrigger echoes it and U registers for T's key, not ours

# IMPLEMENTED: the deck5 tester skill
class SkillExtraPoint extends CardModifierSkill:
