    game.add_line_score(row_of(data), 10)
    game.register_combo(combo_key())

# IMPLEMENTED — the global cousin of StampDoubleTrigger
class SkillEchoingTrigger extends CardModifierSkill:
  func on_mod_triggered(mod) -> void:
    if not mod.is_echo and not game.state.echoed_this_pass.has(mod.data):
      game.state.echoed_this_pass.append(mod.data)  # per-pass ledger, GameData
      mod.retrigger_once()  # echo flag prevents infinite regress
  # SEAM: on_mod_triggered listening to ALL mods = effects observing effects

# SEAM: hooks are just method names — remapping needs a DECORATOR that
# forwards one event as another. NEEDS NEW SYSTEM: modifier proxy/decorator.
class ProxyRemap extends CardModifier:
  var inner : CardModifier
  var map : Dictionary  # {&'on_discard': &'on_score'}
  func _get(hook): return inner  # has_method must answer for mapped hooks
  func on_discard() -> void: inner.call(map[&'on_discard'], fake_result())
# Dragoman wraps target.skill = ProxyRemap.new(target.skill, map); relink!

# SEAM: statuses must duplicate() at EVERY application and merge by class —
# mass propagation is the stress test of both rules at once.
class SkillContagion extends CardModifierSkill:
  func on_next() -> void:
    for n : CardData in adjacent_cards(data):
      for st : CardModifierStatus in n.statuses:
        for far : CardData in adjacent_cards(n):
          game.defer(func(): far.add_status(st.duplicate()))  # merge-by-class dedupes

# SEAM: status identity is the class itself (merge-by-class) — conversion
# means destroy-and-remint, never in-place mutation.
class SkillAlchemist extends CardModifierSkill:
  func on_cue() -> void:  # NEEDS NEW HOOK: on_cue
    var t : CardData = cue_target()
    var n : int = t.status_count(cue_from_class())
    game.defer(func():
      t.remove_status_class(cue_from_class())
      t.add_status(cue_to_class().new().with_count(n)))  # fresh instance, relinked

# SEAM: §4d sanctions mid-flight re-routing — prop.set_route from any hook.
class SkillNet extends CardModifierSkill:
  func on_prop_passing(prop) -> Variant:
    if prop.is_ballistic and not game.state.net_used:
      game.state.net_used = true
      prop.set_route(route_to(cue_or_hash_target(data)))  # never touch at/route raw
      return NEGATE_PASS  # this pass negated; the re-aimed pass is the real one
    return null

# SEAM: spawn plans are DATA (PropSpawner) built before run_props — a hook
# that edits the plan pre-flight makes the whole prop economy moddable.
# NEEDS NEW HOOK: on_spawn_plan(spawners) before Game.run_props
class SkillPropMaster extends CardModifierSkill:
  func on_spawn_plan(spawners : Array[PropSpawner]) -> void:
    for s : PropSpawner in spawners:
      s.remaining += 1  # factory stays PURE; the plan is what mutates

# SEAM: U is data on GameData (combo_classes) — so it is tradeable.
class SkillExchange extends CardModifierSkill:
  func on_after_score() -> void:
    if cue_mode() == SELL:
      var extra : int = max(0, game.state.combo_classes.size() - 3)
      game.add_line_score(0, RATE * extra)
    else:
      game.state.combo_carry += 1  # next act: register_combo('carried:'+str(i))

# SEAM: effect-frequency introspection — the dispatch layer keeps a ledger.
class SkillCritic extends CardModifierSkill:
  func on_mod_triggered(mod) -> void:
    game.state.trigger_tally[mod.combo_key('')] += 1  # per-act ledger, GameData
  func on_after_score() -> void:
    game.state.silenced_next_act = argmax(game.state.trigger_tally)
    for key : String in keys_with_count(game.state.trigger_tally, 1):
      game.add_line_score(0, FRESH_PTS)

# SEAM: hook TIMING as a modifier concern — a deferred-dispatch queue.
# NEEDS NEW SYSTEM: hook scheduler (capture instead of dispatch, flush later)
class SkillConductor extends CardModifierSkill:
  func on_active() -> void: game.state.hold_hooks = [&'on_next']
  func on_run_scorer() -> void:
    for held : HeldCall in player_order_ui(game.state.held_calls):
      game.invoke_mod(held.mod, held.hook)  # flushed at the downbeat
    game.state.held_calls.clear()

# SEAM: result-transform middleware — run_all_mods results become interceptable.
# NEEDS NEW SYSTEM: hook-result middleware chain (wrap, invert, veto)
class SkillLoophole extends CardModifierSkill:
  var target_hazard : CardModifier
  func on_active() -> void:
    game.add_middleware(target_hazard, func(hook, result):
      return invert_result(hook, result))  # NEGATE_PASS->pass, deny->allow, -x->+x
  func on_deactive() -> void: game.remove_middleware(target_hazard)

# SEAM: skills as composable fragments. NEEDS NEW SYSTEM: skill composition
# (shared with the Dubplate) — a ComposedSkill holding N hook implementations.
class SkillApprentice extends CardModifierSkill:
  var learned : ComposedSkill = ComposedSkill.new()
  func on_mod_triggered(mod) -> void:
    if not game.state.observed_this_show and mod.data != data:
      game.state.observed_this_show = true
      learned.absorb(mod)  # clones the fired hook's implementation, max 3
      data.skill = learned; GameData.relink_card_backrefs(data)

# SEAM: deterministic Submit/Next is load-bearing (pending-action replay) —
# an act event log already all but exists. NEEDS NEW SYSTEM: act event log
# capture + re-fire (the replay infra promoted to a player verb).
class SkillGroundhog extends CardModifierSkill:
  func on_cue() -> void:
    for entry : LogEntry in game.state.last_act_log:
      game.invoke_mod(entry.mod, entry.hook)  # fresh targets, same sequence
    game.register_combo(combo_key())

# SEAM: Board's RESOLVE phase — anchors are engine vocabulary (OnTop /
# ColumnStart / ColumnEnd); a mod overriding resolution makes anchors moddable.
# NEEDS NEW HOOK: on_resolve_anchor(request) -> anchor override
class SkillSurveyor extends CardModifierSkill:
  func on_resolve_anchor(req : MoveRequest) -> Variant:
    if req.is_player_drop:
      return Board.ColumnStart.new(req.dest_x, req.dest_col)
    return null  # automated moves keep their own anchors

# SEAM: temporary modifiers with a lifecycle — composition-lite plus cleanup.
class SkillGhostWriter extends CardModifierSkill:
  func on_game_start() -> void:
    var host : CardData = pick_prop_card(game.state)
    host.skill = clone_effect(run_state().last_show_log.front())
    host.meta.temp_skill = true; GameData.relink_card_backrefs(host)
  func on_game_end() -> void:
    for c : CardData in cards_with_meta(&'temp_skill'):
      c.skill = null  # the ink fades; no relink needed for null

# SEAM: combo identity is data (combo_key -> string; U dedupes on it) —
# making the key generative turns the U economy itself moddable.
class SkillDramaturg extends CardModifierSkill:
  var edited : CardData
  func on_mod_triggered(mod) -> void:
    if mod.data == edited:
      game.register_combo(mod.combo_key('') + ':' + str(game.state.trigger_serial))
      game.state.trigger_serial += 1
  # the duplicate_class_scale lever (delta) exists for exactly this abuse

# SEAM: act atomicity. Submit is one deterministic span (pending-action
# replay + undo cancel + fame banking all assume it). Splitting it means:
# NEEDS NEW SYSTEM: split-act resolution — a persisted half-act marker
class SkillTimeSignature extends CardModifierSkill:
  func on_run_scorer() -> void:
    score_all_rows(game.state)
    game.state.pending_half_act = true  # survives save/quit like pending_action
  func on_next() -> void:
    if game.state.pending_half_act:
      score_all_cols(game.state); game.state.pending_half_act = false
      game.apply_act_score()

# SEAM: props are autonomous and replay-deterministic — player steering must
